from agent.paper_reader import PaperReaderAgent
from agent.utils.load_pdf import Paper
from agent.llm import LLM
from agent.memory_writer import MemoryWriterAgent

import time



def test_pdf_load():
    path = "files/EverMemOS- A Self-Organizing Memory Operating System for Structured Long-Horizon Reasoning.pdf"
    paper = Paper(path)
    print(paper.table_of_contents)


def test_llm():
    llm = LLM()
    messages = [
        {"role": "system", "content": "You are a helpful assistant."},
        {"role": "user", "content": "What is the capital of France?"}
    ]
    response = llm.chat(messages)
    print(response)


def test_paper_reader():
    llm = LLM()
    agent = PaperReaderAgent(llm)

    start_time = time.time()
    summaries = agent.read_paper("files/EverMemOS- A Self-Organizing Memory Operating System for Structured Long-Horizon Reasoning.pdf")
    print(summaries)
    end_time = time.time()
    print(f"Execution time: {end_time - start_time} seconds")


def test_paper_reader_output():
    output = {'Abstract': 'The abstract introduces EverMemOS, a self-organizing memory operating system for LLMs that implements an engram-inspired lifecycle. It consists of three phases: Episodic Trace Formation (creating MemCells), Semantic Consolidation (organizing MemCells into thematic MemScenes), and Reconstructive Recollection (performing agentic retrieval). The system is evaluated on LoCoMo, LongMemEval, and PersonaMem-v2, showing significant performance improvements over state-of-the-art methods.', 'Introduction': 'The page concludes the introduction by stating that many failures stem from poor integration of fragmented experiences, not missing information, and identifies the absence of a mechanism to transform episodic experiences into coherent knowledge structures as a key limitation. It then introduces EverMemOS as a unified Memory Operating System that models memory as a dynamic lifecycle, aiming to transform fragmented experiences into stable knowledge structures through three phases: Episodic Trace Formation, Semantic Consolidation, and Reconstructive Recollection. It states EverMemOS draws on biological memory principles but does not aim to simulate them at a neural level, illustrating its advantage over fragment-based systems with a drink recommendation example. It summarizes empirical superiority on benchmarks and lists three contributions: System Design, Innovative Method, and Empirical Validation.', 'Related Work': "The page covers two subsections of Related Work. The first, 'Memory Mechanisms in LLMs', discusses context window extension techniques (sparse attention, recurrence, length extrapolation) and their limitations, including the 'Lost-in-the-Middle' phenomenon. It also covers retrieval-augmented generation (RAG) and parametric memory approaches, noting their respective issues with retrieval quality and forgetting, and the lack of a unified principle in hybrid methods. The second subsection, 'Memory Systems', reviews early differentiable memory systems (NTM/DNC/Key-Value memories) and their scaling issues. It then discusses memory in LLM agents, noting the shift towards persistent state integration and the introduction of episodic, semantic, and hierarchical task memory, while pointing out limitations like fragmented text units. Finally, it reviews recent Memory Operating Systems (e.g., Nemori, MemoryOS, Mem0, Zep, MemOS), characterizing their focus on storage optimization or fact maintenance, and positions EverMemOS as distinct for its three-phase lifecycle that transforms episodic traces into semantic structures.", 'Memory Mechanisms in LLMs': "The page covers subsection 2.1 Memory Mechanisms in LLMs. It details Context Window Extension techniques (sparse attention, recurrence, length extrapolation) and their limitation due to the 'Lost-in-the-Middle' phenomenon. It then details Retrieval-Augmented and Parametric Memory, discussing RAG's reliability dependency on retrieval quality, parametric approaches' suffering from forgetting and instability, and hybrid approaches' lack of a unified organizational principle for persistent memory.", 'Memory Systems': 'The page covers subsection 2.2 Memory Systems. It discusses Early Computational Memory systems (NTM/DNC/Key-Value memories) and their scaling limitations. It then covers Memory in LLM Agents, noting a shift to persistent state integration and recent systems introducing episodic, semantic, and hierarchical task memory, but critiques their reliance on fragmented text units and limited consolidation. Finally, it discusses Memory Operating Systems like Nemori, MemoryOS, Mem0, Zep, and MemOS, noting their focus on storage optimization or fact maintenance, and distinguishes EverMemOS by its three-phase lifecycle for transforming traces into semantic structures.', 'EverMemOS': "The page introduces the EverMemOS framework. The 'Framework Overview' subsection states it is inspired by the biological engram lifecycle and follows a three-phase workflow: Episodic Trace Formation, Semantic Consolidation, and Reconstructive Recollection. The 'Memory Primitives' subsection defines the core atomic unit, the MemCell, as a tuple c = (E, F, P, M). It details its components: Episode (E) as a third-person narrative, Atomic Facts (F) as discrete verifiable statements, Foresight (P) as forward-looking inferences with validity intervals, and Metadata (M). The 'Phase I: Episodic Trace Formation' subsection describes the three-step pipeline to transform interaction history D into MemCells. It outlines the steps: Contextual Segmentation using a Semantic Boundary Detector with LLM prompting, Narrative Synthesis to create a concise Episode (E), and Structural Derivation to extract Atomic Facts (F) and generate Foresight (P) with validity intervals. The 'Phase II: Semantic Consolidation' subsection introduces the online mechanism for organizing MemCells. It describes Incremental Semantic Clustering, where a new MemCell's embedding is compared to existing MemScene centroids; it is assimilated if similarity exceeds a threshold τ, otherwise a new MemScene is created.", 'Framework Overview': 'The page covers subsection 3.1 Framework Overview. It states EverMemOS draws inspiration from the biological engram lifecycle (Josselyn et al., 2015) and follows a three-phase workflow: (1) Episodic Trace Formation encodes interaction streams into MemCells; (2) Semantic Consolidation organizes MemCells into MemScenes and updates user profiles; and (3) Reconstructive Recollection performs MemScene-guided retrieval under the principle of necessity and sufficiency.', 'Memory Primitives': 'The page covers subsection 3.2 Memory Primitives. It defines the MemCell as the atomic unit, a tuple c = (E, F, P, M). It details each component: E (Episode) as a concise third-person narrative; F (Atomic Facts) as discrete, verifiable statements; P (Foresight) as forward-looking inferences with validity intervals; and M (Metadata) as contextual grounding. It states this structure turns memory into a temporally grounded representation.', 'Phase I: Episodic Trace Formation': 'The page begins subsection 3.3 Phase I: Episodic Trace Formation. It states this phase, grounded in the engram concept (Josselyn et al., 2015), transforms the unbounded interaction history stream D = {d1, ..., dT} into discrete, stable memory traces (MemCells) via a three-step pipeline to distill semantic signal from noisy data.', 'Phase II: Semantic Consolidation': 'The page details the Semantic Consolidation phase, which organizes MemCells into higher-order structures via incremental semantic clustering. When a new MemCell arrives, its embedding is computed and compared to the nearest MemScene centroid; if similarity exceeds threshold τ, it is assimilated and the scene representation is updated incrementally; otherwise, a new MemScene is instantiated. This online process maintains thematic structure in real-time without batch reprocessing. Scene-driven profile evolution updates a compact User Profile from aggregated evidence; when a MemCell is assimilated, the system updates a concise scene summary and refreshes the user profile by prompting over these summaries, helping separate stable traits from temporary states. The profile includes explicit facts and implicit traits, updated online with recency-aware updates and conflict tracking.', 'Phase III: Reconstructive Recollection': 'Retrieval in EverMemOS is modeled as an active reconstruction process guided by necessity and sufficiency. Given a query q, EverMemOS performs agentic retrieval grounded in MemScenes. The process includes MemScene Selection via dense and BM25 retrieval over Atomic Facts F with Reciprocal Rank Fusion (RRF), scoring each MemScene by maximum relevance among its MemCells. Episode and Foresight Filtering pools Episodes from selected MemScenes, re-ranks them, and retains only time-valid Foresight where tnow ∈ [tstart, tend]. Agentic Verification and Query Rewriting uses an LLM-based verifier for sufficiency, triggering query rewriting if insufficient. Two downstream Task Modes are Memory-Augmented Reasoning (using retrieved Episodes as context) and Memory-Augmented Chat (incorporating User Profile and time-valid Foresight).', 'Experiments': 'The page presents the main results from Tables 1 and 2, showing EverMemOS outperforming baselines (MemoryOS, Mem0, MemU, MemOS, Zep) on LoCoMo and LongMemEval under GPT-4o-mini and GPT-4.1-mini backbones. It includes Figure 6 on the performance-cost frontier and Table 3 comparing boundary detection strategies.', 'Experimental Setup': "Benchmarks include LoCoMo (1,540 questions over 10 ultra-long dialogues, ~9K tokens each, spanning single-hop, multi-hop, and temporal questions) and LongMemEval (S-setting, ~115k tokens per conversation, 500 questions requiring full-history parsing). Baselines are state-of-the-art memory systems: Zep (Rasmussen et al., 2025), Mem0 (Chhikara et al., 2025), MemOS (Li et al., 2025), MemoryOS (Kang et al., 2025), and MemU. Fair comparison standardizes the answer-generation backbone across methods while keeping each baseline's official memory configuration unchanged. For LongMemEval, baseline scores are from the official MemOS leaderboard. Evaluation Protocol uses the LLM-as-a-judge protocol with GPT-4o-mini and two auxiliary judge models, averaging scores across three judgments in a blind setting. Implementation Details: EverMemOS uses GPT-4.1-mini (or GPT-4o-mini) for all reasoning and memory operations. Retrieval uses hybrid dense+BM25 fusion (RRF) with re-ranking. Quantitative experiments use Memory-Augmented Reasoning unless specified.", 'Scene-Driven Profile Evolution': 'The page describes scene-level consolidation updating a compact User Profile from aggregated evidence. When a new MemCell is assimilated into a MemScene, EverMemOS updates a concise scene summary and refreshes the user profile by prompting over these summaries, helping separate stable traits from temporary states. The system maintains a compact profile of explicit facts (including time-varying measurements) and implicit traits, updated online from scene summaries with recency-aware updates and conflict tracking.', 'Main Results': 'The page reports main results on LoCoMo and LongMemEval benchmarks. EverMemOS outperforms the strongest baseline (Zep) on LoCoMo by 7.0% and 9.2% with different backbones, and outperforms MemOS on LongMemEval by 6.7%. Key observations include: lifecycle-driven performance gains due to structured consolidation; significant gains on LoCoMo multi-hop (+19.7%) and temporal (+10.0%) tasks, and LongMemEval knowledge update (+20.6%), attributed to MemScenes; and a favorable accuracy-efficiency trade-off, with Reconstructive Recollection avoiding noise accumulation. Tables 1 and 2 present detailed results.', 'Ablation Study': 'The page presents an ablation study on LoCoMo isolating contributions of MemScenes, MemCells, and episode segmentation. Figure 4 shows performance degrades stepwise when removing structure: w/o MemScenes weakens cross-turn aggregation, w/o MemCells drops stable semantic units, and w/o external memory collapses long-horizon performance. The effectiveness of semantic episode segmentation is evaluated against fixed heuristics and ground-truth boundaries. Table 3 shows semantic segmentation (EverMemOS) consistently outperforms fixed heuristics and even Session (Oracle), with robustness across boundary-detection backbones (accuracy changes ≤0.7 points).', 'Hyperparameter Analysis': 'The page analyzes the impact of retrieval hyperparameters N (MemScenes) and K (episodes), noting performance saturates at N=10 and adopts N=10, K=10 as the default configuration.', 'Profile Study': 'The page reports an ablation study evaluating the effect of the consolidated user profile on the PersonaMem-v2 benchmark. Adding the User Profile to episodic evidence improves overall accuracy by 9.32 percentage points over an episodes-only baseline (53.25% vs. 43.93%), demonstrating that semantic consolidation provides a complementary signal beyond raw episodic retrieval.', 'Case Study': "The page presents three case studies illustrating EverMemOS's capabilities beyond standard benchmarks: (1) Episodic Memory Recall: Accurately reconstructs a specific past injury (Grade II ankle sprain during badminton) from a user's history, contrasting with a generic explanation from a system without memory. (2) Longitudinal Profile Modeling: Uses consolidated user profile data (sustained waist reduction from 104cm to 96cm and stable weight) to provide trajectory-consistent goal-setting advice. (3) Experience-Grounded Foresight: Leverages a past negative experience (overcrowding and ticket access issues in Beijing) to generate proactive, personalized recommendations for a future Europe trip (prioritizing advance reservations and off-peak visits).", 'Conclusion': 'The page concludes by discussing limitations of the proposed memory system, including increased latency and computational cost from multi-phase memory construction and retrieval relative to single-pass baselines. It notes that while components can be cached or run asynchronously, improving end-to-end efficiency remains future work. It also highlights a lack of benchmarks for stress-testing ultra-long timelines, motivating future benchmarks for long-term memory organization and consolidation.', 'References': 'The page lists a comprehensive set of references for the paper, including works on long-context transformers (Longformer, RMT, Transformer-XL, Big Bird), memory-augmented models (Neural Turing Machines, LongMem, MemGPT), retrieval-augmented generation (RAG, In-context RALM), continual learning, agent memory systems (Mem0, PersonaMem-v2, Memory OS, Zep, Mirix, Nemori), evaluation benchmarks (LongMemeval, PersonaMem-v2), and related surveys (Ferrag et al., Xi et al., Yehudai et al.).', 'Evaluation Details': "The page presents detailed evaluation settings, including the use of GPT-4.1-mini and GPT-4o-mini as backbones for LoCoMo, baseline execution protocols, and handling of LongMemEval via an official leaderboard. It describes EverMemOS's hybrid retrieval configuration, MemBase statistics, and construction hyperparameters (Tables 5 and 6). It notes a 31.0% query rewriting frequency on LoCoMo and specifies the default evaluation mode as Memory-Augmented Reasoning.", 'Evaluation Settings and Fair Comparison': 'The page details the evaluation settings for fair comparison, including the standardization of backbones for final answer generation, the executability of baselines using official APIs, and the protocol for LongMemEval. It specifies the retrieval configuration for EverMemOS, including the use of Qwen3-Embedding-4B and Qwen3-Reranker-4B models, and the retrieval of top-10 MemScenes and 10 Episodes.', 'LLM-as-Judge Reliability': "The page presents reliability metrics for GPT-4o-mini as a judge, reporting a Cohen's κ of 0.891 on LoCoMo and 0.978 on LongMemEval, with corresponding accuracies of 0.984 and 0.992. The results indicate the model achieves human-level reliability for answer verification.", 'Token Cost Breakdown': 'The page provides a detailed token cost breakdown for LoCoMo evaluation using GPT-4.1-mini and GPT-4o-mini backbones. It maps token usage to EverMemOS phases: Phase I (add) consumes 9.42M and 9.34M tokens respectively; Phase III (search+answer) consumes 10.27M and 9.31M tokens. The evaluate stage (LLM-as-judge) consumes 2.38M and 2.17M tokens.', 'PersonaMem v2: Full Comparison Results': 'Table 9 presents the full comparison on PersonaMem v2 (32k) across 9 scenarios, showing EverMemOS achieving the highest overall accuracy (53.25%). The table includes accuracy scores for each scenario (e.g., Consultation: 51.03, Email (Personal): 53.85, Knowledge Query: 63.68) and notes which systems support a profile feature.', 'Additional Analyses': 'The page includes Table 10 showing accuracy vs. recall statistics on LoCoMo, with accuracy (71.80% for K=1, 87.81% for K=3) exceeding recall (65.06% for K=1, 86.32% for K=3). It explains that recall can underestimate retrieval usefulness due to distributed evidence, noting that increasing K from 1 to 3 reduces zero-recall cases by 71% (429 to 125). Three illustrative cases are provided where answers remain correct despite missing annotated evidence: redundant identity facts, distributed activity mentions, and inference from related signals.', 'Hyperparameter Sensitivity and Efficiency Trade-off': 'The page analyzes the hyperparameters N (MemScene budget) and K (episode budget) in a simplified one-shot retrieval setting. It reports that increasing N improves recall and accuracy but saturates quickly, with N=10 providing strong recall. It states K=10 is chosen to cover difficult instances. A cost-accuracy frontier shows EverMemOS can achieve lower token usage and higher accuracy than baselines at moderate K values.', 'Accuracy Exceeding Recall on LoCoMo': 'The page analyzes why accuracy can exceed recall on LoCoMo, attributing it to information redundancy and non-unique evidence annotations. It provides statistics showing that 12-20% of questions are answered correctly even with zero recall of annotated evidence. Three illustrative cases are provided: redundant identity facts, distributed activity mentions, and inference from related signals. Increasing K from 1 to 3 reduces zero-recall cases by 71%.', 'Profile Extraction Example': 'The page presents Table 11, an abridged profile extraction example showing de-identified evidence snippets (e.g., user messages about waist circumference and fatty liver) and the resulting user profile, which includes explicit facts (e.g., waist baseline 104 cm, latest 95 cm) and implicit traits (e.g., self-management style, preference for actionable advice).', 'Prompts for Agentic Retrieval': 'The page contains two detailed prompt templates for agentic retrieval components. The first is for an expert information retrieval evaluator to assess sufficiency of retrieved documents against a query, with instructions for analyzing query needs, evaluating document evidence, and a strict JSON output format. The second is for an expert at query reformulation to generate 2-3 complementary queries when retrieval is insufficient, detailing strategy selection (e.g., Pivot, Temporal Calculation) and query style requirements (Keyword Combo, Natural Question, Hypothetical Statement), also with a strict JSON output format.', 'End-to-End Inference Trace (LoCoMo Multi-Hop Example)': "The page provides a detailed end-to-end inference trace for a multi-hop question from the LoCoMo dataset (conversation locomo_6). The question is 'Does James live in Connecticut?'. The trace outlines the MemBase hierarchy (49 MemScenes / 91 MemCells) and the two-round agentic retrieval process (scene_top_k N=10, response_top_k K=10). Round 1 retrieval of top 10 MemScenes (31 MemCells) is deemed insufficient (is_sufficient=false) as it lacks explicit residence confirmation. The controller generates three refined queries. Round 2 retrieval with these queries yields 40 additional candidates; the top-ranked MemCell ('James Adopts Shelter Dog Ned...') provides key evidence: James adopted a dog from a shelter in Stamford. The final inference chains this evidence with the prior mention of moving near McGee's Bar to conclude James likely lives in Connecticut. The answer is judged correct by 3/3 LLM judges."}
